import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";const o=JSON.parse(`{"title":"Створення проєкту","description":"Покрокова інструкція зі створення нового проєкту мода за допомогою генератора шаблонів модів Fabric.","frontmatter":{"title":"Створення проєкту","description":"Покрокова інструкція зі створення нового проєкту мода за допомогою генератора шаблонів модів Fabric.","authors":["Cactooz","IMB11","radstevee","Thomas1034"],"resources":{"https://fabricmc.net/develop/template/":"Генератор шаблона мода Fabric","https://fabricmc.net/develop/":"Розробка з сайтом Fabric"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/creating-a-project.md","filePath":"translated/uk_ua/develop/getting-started/creating-a-project.md","lastUpdated":1774518827000}`);var s={name:`uk_ua/develop/getting-started/creating-a-project.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Створення проєкту <a class="header-anchor" href="#h1" aria-label="Permalink to “Створення проєкту”">​</a></h1><p>Fabric надає простий спосіб створити новий проєкт мода за допомогою генератора шаблона мода Fabric — якщо ви хочете, ви можете вручну створити новий проєкт, використовуючи приклад сховища модів, вам слід звернутися до <a href="#manual-project-creation">створення проєкту вручну</a> розділ.</p><h2 id="generating-a-project" tabindex="-1">Генерація проєкту <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Генерація проєкту”">​</a></h2><p>Ви можете використати <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">генератор шаблона мода Fabric</a>, щоб створити новий проєкт для свого мода — вам слід заповнити обов’язкові поля, як-от назва мода, назва пакета, і версію Minecraft, для якої ви хочете розробляти.</p><p>Назва пакета повинно бути малим реєстром, розділеним крапками та унікальним, щоб уникнути конфліктів з пакетами інших програмістів. Зазвичай він форматується як зворотний інтернет-домен, наприклад <code>com.example.example-mod</code>.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖЛИВО</p><p>Обов’язково запам’ятайте ID свого мода! Щоразу, коли ви знайдете <code>example-mod</code> у цих документах, особливо в шляхах до файлів, вам доведеться замінити його на свій власний.</p><p>Наприклад, якщо ID вашого мода був <strong><code>my-cool-mod</code></strong>, замість <em><code>resources/assets/example-mod</code></em> використовуйте <strong><code>resources/assets/my-cool-mod</code></strong>.</p></div><p><img src="/assets/develop/getting-started/template-generator.png" alt="Попередній перегляд генератора" loading="lazy"></p><p>Якщо ви бажаєте використовувати Kotlin або мапінгів Fabric Yarn замість стандартних мапінгів Mojang або хочете додати генератори даних, ви можете вибрати відповідні параметри в розділі <code>Advanced Options</code>.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>У прикладах коду, наведених на цьому сайті, використовуються <a href="./../porting/mappings/#mappings">офіційні назви Mojang</a>. Якщо у вашому моді не використовуються ті самі мапінги, у яких написані ці документи, вам потрібно буде конвертувати приклади за допомогою таких сайтів, як <a href="https://mappings.dev/" target="_blank" rel="noreferrer">mappings.dev</a> або <a href="https://linkie.shedaniel.dev/mappings?namespace=yarn&amp;translateMode=ns&amp;translateAs=mojang_raw&amp;search=" target="_blank" rel="noreferrer">Linkie</a>.</p></div><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Розділ додаткових параметрів" loading="lazy"></p><p>Коли ви заповните необхідні поля, натисніть кнопку <code>Generate</code>, і генератор створить для вас новий проєкт у формі zip-файлу.</p><p>Вам слід розпакувати цей zip-файл у вибране вами місце, а потім відкрити розпаковану теку в середовищі IDE.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Вибираючи шлях до свого проєкту, слід дотримуватися таких правил:</p><ul><li>Уникайте каталогів хмарних сховищ (наприклад, Microsoft Onedrive)</li><li>Уникайте не ASCII символів (наприклад, емодзі, літери з акцентами)</li><li>Уникайте пробілів</li></ul><p>Прикладом «хорошого» шляху може бути: <code>C:\\Projects\\YourProjectName</code></p></div><h2 id="manual-project-creation" tabindex="-1">Створення проєкту власноруч <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Створення проєкту власноруч”">​</a></h2><div class="info custom-block"><p class="custom-block-title">ПЕРЕДУМОВИ</p><p>Вам знадобиться встановити <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>, щоб клонувати приклад сховища модів.</p></div><p>Якщо ви не можете використовувати генератор шаблонів Fabric Mod Generator, ви можете створити новий проєкт вручну, виконавши ці дії.</p><p>По-перше, клонуйте приклад репозиторію модів за допомогою Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example-mod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Це призведе до клонування репозиторію в нову теку під назвою <code>example-mod</code>.</p><p>Потім вам слід видалити теку <code>.git</code> із клонованого репозиторію, а потім відкрити проєкт. Якщо тека <code>.git</code> не показується, вам слід увімкнути показ прихованих файлів у вашому файловому менеджері.</p><p>Коли ви відкриєте проєкт в IDE, він має автоматично завантажити налаштування Gradle проєкту та виконати необхідні завдання налаштування.</p><p>Знову ж таки, як згадувалося раніше, якщо ви отримуєте сповіщення про сценарій збірки Gradle, вам слід натиснути кнопку <code>Import Gradle Project</code>.</p><h3 id="modifying-the-template" tabindex="-1">Змінення шаблону <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Змінення шаблону”">​</a></h3><p>Після того як проєкт буде імпортовано, ви повинні змінити деталі проєкту, щоб вони відповідали деталям вашого мода:</p><ul><li>Змініть файл <code>gradle.properties</code> проєкту, щоб змінити властивості <code>maven_group</code> і <code>archive_base_name</code> відповідно до деталей вашого мода.</li><li>Змініть файл <code>fabric.mod.json</code>, щоб змінити властивості <code>id</code>, <code>name</code> і <code>description</code> відповідно до деталей вашого мода.</li><li>Переконайтеся, що ви оновили версії Minecraft, мапінги, Завантажувач і Loom, які можна отримати через <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a>, щоб відповідати версіям, на які ви хочете націлити.</li></ul><p>Очевидно, ви можете змінити назву пакета та основний клас мода, щоб відповідати деталям вашого мода.</p>`,26)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};